<!DOCTYPE html><html><head><meta charset="utf-8">
<link href="https://fonts.googleapis.com/css2?family=Exo+2:wght@300;400;500;600&display=swap" rel="stylesheet">
<style>
*,*::before,*::after{margin:0;padding:0;box-sizing:border-box}
html,body{background:transparent}
#ais{--c:#8fe9ff;max-width:520px;margin:10px auto 18px;font-family:'Exo 2',sans-serif}
#ais .say{position:relative;padding:3px 8px 3px 16px;font-size:15px;line-height:1.6;color:#eaf8fc;
  border-left:1px solid rgba(143,233,255,.4);opacity:0;animation:aisIn .6s ease .05s forwards}
#ais .say::before{content:'';position:absolute;left:-1px;top:0;width:1px;height:0;background:var(--c);box-shadow:0 0 8px var(--c);animation:aisFill 1.1s ease .05s forwards}
#ais .car{display:inline-block;width:7px;height:15px;background:var(--c);margin-left:4px;vertical-align:-2px;box-shadow:0 0 8px var(--c);animation:aisCaret 1s steps(1) infinite}
@keyframes aisIn{to{opacity:1}}
@keyframes aisFill{to{height:100%}}
@keyframes aisCaret{0%,100%{opacity:1}50%{opacity:0}}
</style></head>
<body>
<span id="hx" style="display:none">$1</span><span id="tx" style="display:none">$2</span>
<div id="ais"><div class="say"><span id="out"></span><span class="car"></span></div></div>
<script>
(function(){
  function txt(id){var e=document.getElementById(id);return e?(e.textContent||'').replace(/^\s+/,'').replace(/\s+$/,''):'';}
  var hex=txt('hx'), body=txt('tx');
  document.getElementById('out').textContent=body;
  var h=hex.replace(/[^#0-9a-fA-F]/g,'');
  if(h&&h.charAt(0)!=='#')h='#'+h;
  if(/^#([0-9a-fA-F]{3}|[0-9a-fA-F]{6}|[0-9a-fA-F]{8})$/.test(h))document.getElementById('ais').style.setProperty('--c',h);
})();
</script>
